#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5,mod=998244353;
int n,a[N],dp[N],ans=0;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	dp[1]=1;
	for(int i=1;i<=n;i++){
		ans+=dp[i],ans%=mod;
		for(int j=i+a[i];j<=n;j+=a[i])
			dp[j]+=dp[i],dp[j]%=mod;
	}
	printf("%d",ans);
	return 0;
}
